INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('technology_software_engineer', 'Technology', 'Software Engineer', 'I am writing to express my strong interest in the {role_type} position at {company_name}. With {years} years of technology leadership experience in the {branch}, I bring a unique combination of technical expertise, operational discipline, and mission-focused delivery that aligns perfectly with your team''s goals.', 'During my tenure in the {branch}, I led teams of {team_size}+ professionals and managed operations valued at {budget}+. I consistently delivered results in high-pressure environments, including {achievement}. My experience translates directly to the {role_type} role because I understand the importance of precision, accountability, and continuous improvement.', 'What sets me apart is my ability to bridge the gap between military operations and civilian business objectives. I hold {certifications} and have a proven track record in {skills}. I am particularly drawn to {company_name} because of your commitment to {company_value}, which resonates with my own professional values of integrity, teamwork, and excellence.', 'I am confident that my combination of leadership experience, technical skills, and mission-focused mindset would make me a valuable addition to your team. I welcome the opportunity to discuss how my background can contribute to {company_name}''s continued success. Thank you for your consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","team_size":"Number of personnel led","budget":"Budget or assets managed","achievement":"Key military achievement","certifications":"Relevant certifications held","skills":"Key transferable skills","company_value":"Company value that resonates"}'::jsonb, 'Military